# ── Crypto helpers ────────────────────────────────────────────────────────────
def _sp_xor(d, k):
    return bytes(b ^ k[i % len(k)] for i, b in enumerate(d))

def _sp_enc(data):
    return _b64.urlsafe_b64encode(_sp_xor(_json.dumps(data).encode(), _SP_ENC_KEY)).decode()

def _sp_dec(s):
    try:
        return _json.loads(_sp_xor(_b64.urlsafe_b64decode(s.encode()), _SP_ENC_KEY).decode())
    except Exception:
        return {}

def _sp_read(path):
    try:
        with open(path) as f:
            return _sp_dec(f.read())
    except Exception:
        return {}

def _sp_write(path, data):
    _os.makedirs(_SP_DATA_DIR, exist_ok=True)
    with open(path, "w") as f:
        f.write(_sp_enc(data))

# ── Hardware ID ───────────────────────────────────────────────────────────────
def _sp_hwid():
    mac = _uuid.getnode()
    raw = ":".join(format(mac, "012x")[i:i+2] for i in range(0, 12, 2))
    h = _hl.sha256(raw.encode()).hexdigest()[:16].upper()
    return "-".join(h[i:i+4] for i in range(0, 16, 4))

# ── License validation ────────────────────────────────────────────────────────
def _sp_valid(email, hwid, key):
    raw = f"{email.lower().strip()}:{hwid.upper().replace('-','')}"
    sig = _hmac.new(_SP_SECRET.encode(), raw.encode(), _hl.sha256).hexdigest()
    return _hmac.compare_digest(key.replace("-","").upper(), sig[:16].upper())

