# ── Main check ────────────────────────────────────────────────────────────────
def _sp_check():
    hwid = _sp_hwid()
    lic = _sp_read(_SP_LIC_FILE)
    if lic.get("email") and lic.get("key") and _sp_valid(lic["email"], hwid, lic["key"]):
        return True

    trial = _sp_read(_SP_TR_FILE)
    if not trial.get("install_date"):
        trial = {"install_date": _dt.datetime.now().isoformat()}
        _sp_write(_SP_TR_FILE, trial)

    install_dt = _dt.datetime.fromisoformat(trial["install_date"])
    days_used  = (_dt.datetime.now() - install_dt).days
    days_left  = max(0, _SP_TRIAL_DAYS - days_used)

    if days_left > 0:
        _sp_trial_notice(days_left)
        return True
    return _sp_expired_dialog()

if not _sp_check():
    _sys.exit(0)
